INSERT INTO `courses` VALUES (1,'2026-04-21 19:00:45.206998',NULL,'2026-04-21 19:14:09.227801','Spring JPA의 기본 개념부터 실무에서 자주 사용하는 연관관계 매핑, 영속성 컨텍스트, 지연 로딩, JPQL, 성능 최적화까지 단계별로 학습하는 실전형 코스입니다.\r\n\r\n단순히 문법을 익히는 것을 넘어, 실제 프로젝트에서 JPA를 사용할 때 마주치는 N+1 문제, 트랜잭션 범위, 엔티티 설계 기준을 함께 다룹니다.\r\n백엔드 개발자로서 데이터베이스와 객체 모델을 안정적으로 연결하는 역량을 키우는 것을 목표로 합니다.',50000,'ACTIVE','/uploads/courses/e72ae78d80524f838388f289fa8b5967.jpeg','Spring JPA 실전 마스터',1,3),(2,'2026-04-21 19:13:49.661529',NULL,'2026-04-21 19:14:09.961838','개발자 취업을 준비하는 수강생을 위한 실전형 취업 캠프입니다.\r\n이 코스에서는 이력서 작성, 포트폴리오 구성, GitHub 정리, 기술 면접 준비, 프로젝트 경험 설명법까지 취업 과정에서 필요한 핵심 요소를 단계별로 학습합니다.\r\n단순한 취업 팁이 아니라, 실제 면접에서 자주 받는 질문과 프로젝트 기반 답변 전략을 함께 다루며 주니어 백엔드 개발자로서 자신 있게 지원할 수 있는 준비 과정을 제공합니다.',70000,'ACTIVE','/uploads/courses/395f30fdb81344a79d5a90aeaa0610c6.jpeg','원티드 취업 캠프',4,3),(1001,'2026-04-22 12:41:00.000000',NULL,'2026-04-22 12:41:00.000000','Spring Boot API Masterclass 01 is a practical dummy course for testing list, detail, payment, enrollment, review, and dashboard screens.',40000,'ACTIVE','/uploads/courses/395f30fdb81344a79d5a90aeaa0610c6.jpeg','Spring Boot API Masterclass 01',1,1001),(1002,'2026-04-22 12:42:00.000000',NULL,'2026-04-22 12:42:00.000000','JPA Performance Tuning 02 is a practical dummy course for testing list, detail, payment, enrollment, review, and dashboard screens.',50000,'ACTIVE','/uploads/courses/395f30fdb81344a79d5a90aeaa0610c6.jpeg','JPA Performance Tuning 02',2,1002),(1003,'2026-04-22 12:43:00.000000',NULL,'2026-04-22 12:43:00.000000','React Practical Workshop 03 is a practical dummy course for testing list, detail, payment, enrollment, review, and dashboard screens.',60000,'ACTIVE','/uploads/courses/395f30fdb81344a79d5a90aeaa0610c6.jpeg','React Practical Workshop 03',3,1003),(1004,'2026-04-22 12:44:00.000000',NULL,'2026-04-22 12:44:00.000000','TypeScript System Design 04 is a practical dummy course for testing list, detail, payment, enrollment, review, and dashboard screens.',70000,'ACTIVE','/upload